const Object _sameBody = Object();

class RedirectRequest {
  final String method;
  final Uri uri;
  final Map<String, String> headers;
  final List<int>? body;

  RedirectRequest({
    required String method,
    required this.uri,
    Map<String, String> headers = const <String, String>{},
    List<int>? body,
  }) : method = method.trim().toUpperCase(),
       headers = Map<String, String>.unmodifiable(headers),
       body = body == null ? null : List<int>.unmodifiable(body) {
    if (this.method.isEmpty) {
      throw ArgumentError.value(method, 'method', 'must not be empty');
    }
    if (!uri.isAbsolute || uri.host.isEmpty) {
      throw ArgumentError.value(uri, 'uri', 'must be an absolute HTTP URI');
    }
  }

  RedirectRequest copyWith({
    String? method,
    Uri? uri,
    Map<String, String>? headers,
    Object? body = _sameBody,
  }) {
    return RedirectRequest(
      method: method ?? this.method,
      uri: uri ?? this.uri,
      headers: headers ?? this.headers,
      body: identical(body, _sameBody) ? this.body : body as List<int>?,
    );
  }
}

class RedirectPolicy {
  static const _redirectStatuses = <int>{301, 302, 303, 307, 308};

  RedirectRequest derive(
    RedirectRequest current, {
    required int statusCode,
    required Uri target,
  }) {
    if (!_redirectStatuses.contains(statusCode)) {
      throw ArgumentError.value(statusCode, 'statusCode', 'not a redirect');
    }
    return current.copyWith(uri: target);
  }
}

