class RedirectResponse {
  static const _redirectStatuses = <int>{301, 302, 303, 307, 308};

  final int statusCode;
  final String location;

  RedirectResponse({required this.statusCode, required this.location}) {
    if (!_redirectStatuses.contains(statusCode)) {
      throw ArgumentError.value(statusCode, 'statusCode', 'not a redirect');
    }
    if (location.trim().isEmpty) {
      throw ArgumentError.value(location, 'location', 'must not be empty');
    }
  }

  Uri resolveFrom(Uri requestUri) => requestUri.resolve(location);
}

