import 'redirect_request.dart';
import 'redirect_response.dart';

class RedirectFollower {
  final RedirectPolicy policy;

  RedirectFollower([RedirectPolicy? policy])
    : policy = policy ?? RedirectPolicy();

  RedirectRequest follow(
    RedirectRequest initial,
    Iterable<RedirectResponse> responses,
  ) {
    var current = initial;
    for (final response in responses) {
      final target = response.resolveFrom(current.uri);
      current = policy.derive(
        current,
        statusCode: response.statusCode,
        target: target,
      );
    }
    return current;
  }
}

