import '../lib/redirect_follower.dart';
import '../lib/redirect_request.dart';
import '../lib/redirect_response.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final initial = RedirectRequest(
    method: 'POST',
    uri: Uri.parse('https://api.example.test/uploads'),
    headers: const <String, String>{
      'Authorization': 'Bearer upload-token',
      'Content-Type': 'application/octet-stream',
      'X-Request-Id': 'req-17',
    },
    body: const <int>[1, 2, 3],
  );

  final result = RedirectFollower().follow(initial, <RedirectResponse>[
    RedirectResponse(statusCode: 307, location: '/uploads/session-17'),
  ]);

  check(
    result.uri.path == '/uploads/session-17',
    'resolves a relative location',
  );
  check(result.method == 'POST', 'temporary redirect preserves the method');
  check(
    result.body?.join(',') == '1,2,3',
    'temporary redirect preserves the body',
  );
  check(
    result.headers['Authorization'] == 'Bearer upload-token',
    'same-authority redirect preserves credentials',
  );
  check(
    result.headers['X-Request-Id'] == 'req-17',
    'ordinary request headers are retained',
  );

  print('public tests passed');
}
